const Content = forwardRef((props: contentProps, contentRef: RefObject<HTMLInputElement>) => {

  const [startX, setStartX] = useState(null);
  const [startY, setStartY] = useState(null);

  const leftDrawerRef = useRef(null)

  let cardClassname = ''
  if (props.type === 'card') {
    cardClassname = props.headerType === 'custom' ? 'PageLayout__body--card--custom-header' : 'PageLayout__body--card'
  }

  useEffect(() => {
    const leftDrawer: any = leftDrawerRef?.current
    const version = props.version
    const isResizeable = props.resizeable
    const type = props.type
    const MIN_WIDTH = 70
    const MAX_WIDTH = 800

    let pageLayoutLeftSideBar: any = props?.leftSidebarRef?.current
    let PageLayoutBody: any = contentRef?.current
    let pageLayoutHead: any = props?.layoutHeaderRef?.current
    let pageLayout: any = props?.pageLayoutRef?.current

    let minWidthPx = MIN_WIDTH, maxWidthPx = MAX_WIDTH

    let resizableLeftMinWidth = typeof props?.resizableLeftMinWidth === 'number' ? props?.resizableLeftMinWidth : MIN_WIDTH
    let resizableLeftMaxWidth = typeof props?.resizableLeftMaxWidth === 'number' ? props?.resizableLeftMaxWidth : MAX_WIDTH

    minWidthPx = (resizableLeftMinWidth >= MIN_WIDTH && resizableLeftMinWidth <= MAX_WIDTH) ? resizableLeftMinWidth : (resizableLeftMinWidth < MIN_WIDTH ? MIN_WIDTH : MAX_WIDTH)
    maxWidthPx = (resizableLeftMaxWidth >= minWidthPx && resizableLeftMaxWidth <= MAX_WIDTH) ? resizableLeftMaxWidth : MAX_WIDTH

    function resize(e) {
      if (pageLayoutLeftSideBar?.classList.contains('PageLayout__leftSidebar--show')) {

        pageLayout.classList.add('PageLayout--resizing')

        let calculatedWidthInRem, calculatedWidthInPx;

        const canResize = (xcord: number) => {
          calculatedWidthInPx = props.noSideNav ? xcord : xcord - 55;
          calculatedWidthInRem = pxToRem(calculatedWidthInPx)

          if (calculatedWidthInPx >= minWidthPx && calculatedWidthInPx <= maxWidthPx) {
            return true
          }
          return false
        }

        const calcAndSetPageLayoutWidth = (calculatedWidthInRem: number) => {
          const [headOffset, marginOffset, bodyOffset] = props.noSideNav ? [0, 0, 0] : [3.45, 3.468, 3.62];
          pageLayoutLeftSideBar.style.setProperty('width', `${calculatedWidthInRem}rem`);
          pageLayoutHead.style.setProperty('width', `calc(100% - ${calculatedWidthInRem + headOffset}rem)`);
          PageLayoutBody.style.setProperty('margin-left', `${calculatedWidthInRem + marginOffset}rem`);
          PageLayoutBody.style.setProperty('width', `calc(100% - ${calculatedWidthInRem + bodyOffset}rem)`);
        }

        if (canResize(e.clientX)) {
          calcAndSetPageLayoutWidth(calculatedWidthInRem)
        }
      }
    }
    let moving = false

    const handleMouseDown = () => {
      moving = true
      document.addEventListener('mousemove', resize, false)
      document.addEventListener('mouseup', handleMouseUp, false)
    }

    const handleMouseUp = () => {
      if (moving) {
        document.removeEventListener('mousemove', resize, false)

        pageLayout.classList.remove('PageLayout--resizing')

        let calculatedWidthInPx = remToPx(parseFloat(pageLayoutLeftSideBar.style.width))
        if (calculatedWidthInPx > (maxWidthPx - 10)) {
          leftDrawer.style.cursor = "w-resize"
        } else if (calculatedWidthInPx < (minWidthPx + 10)) {
          leftDrawer.style.cursor = "e-resize"
        } else {
          leftDrawer.style.cursor = "ew-resize"
        }

        if (props.setCurrentWidth) {
          props.setCurrentWidth(calculatedWidthInPx)
        }

        moving = false
      }
      document.removeEventListener('mouseup', handleMouseUp, false)
    }

    const addRemoveResizeMouseEvent = () => {
      leftDrawer.addEventListener('mousedown', handleMouseDown, false)
    }

    if (leftDrawer && version === 'v2' && isResizeable && type === 'list') {
      addRemoveResizeMouseEvent()
    }

    return () => {
      if (leftDrawer && version === 'v2' && isResizeable && type === 'list') {
        leftDrawer?.removeEventListener('mousedown', handleMouseDown, false)
        document?.removeEventListener('mouseup', handleMouseUp, false)
        document?.removeEventListener('mousemove', resize, false)
      }
    }
  }, [])

  const handleMouseDown = (event) => {
    setStartX(event.clientX);
    setStartY(event.clientY);
  };

  const handleMouseUp = (event) => {
    const endX = event.clientX;
    const endY = event.clientY;
    // Check if it was a click (mouse didn't move much)
    const isClick = Math.abs(endX - startX) < 5 && Math.abs(endY - startY) < 5;

    if (isClick) {
      console.log('Mouse click!');
      props.toggle()
    }
  };

  return useMemo(() => {
    if (props.content !== undefined) {
      return (
        <>
          {props.type === 'edit' ? (

            <div ref={contentRef} onKeyDown={props.onKeyDown} className={['PageLayout__body', props.noSideNav ? 'PageLayout__body--no__sideNav' : ''].filter(Boolean).join(' ')} id="PageLayout__body">
              {props.content.livePreview}
              <div className="PageLayout__body__container" >{props.content.component}</div>
            </div>
          ) : (
            <div ref={contentRef} onKeyDown={props.onKeyDown} className={['PageLayout__body', props.noSideNav ? 'PageLayout__body--no__sideNav' : '', cardClassname].filter(Boolean).join(' ')} data-test-id="cs-page-layout-contentBody">
              {props.content.component}
              {
                props.version === 'v2'
                  ? !props.noLeftNav && <div ref={leftDrawerRef} className="PageLayout__body--left-drawer"
                    onMouseDown={handleMouseDown}
                    onMouseUp={handleMouseUp}
                    onMouseOver={() => {
                      const hamburgerIcon = document.getElementById('PageLayout-hamburger')
                      hamburgerIcon?.classList?.add('PageLayout__head__hamburger__v2')
                    }}
                    onMouseOut={() => {
                      const hamburgerIcon = document.getElementById('PageLayout-hamburger')
                      hamburgerIcon?.classList?.remove('PageLayout__head__hamburger__v2')
                    }}
                    data-test-id="cs-page-layout-leftDrawer"
                  ></div>
                  : <></>
              }
            </div>
          )}
        </>
      )
    } else {
      return null
    }
  }, [props.content, props.content.component, props.toggleStat, startX, startY])
})

const ListLayout = (props: primaryLayoutProps) => {

  const { testId = "cs-list-layout" } = props;

  const [toggleLeftNav, setLeftNav] = useState(true)
  const [toggleLayout, setToggleLayout] = useState(false)
  const sidebar = useRef(null)
  const contentRef = useRef(null);
  const layoutHeaderRef = useRef(null);
  const pageLayoutRef = useRef(null)

  useEffect(() => {
    if (props.type === 'list' && props.initialWidth && !props.noLeftNav) {//
      const DEFAULT_WIDTH = 240
      const initialWidthInpx = props.initialWidth || DEFAULT_WIDTH
      const initialWidthInRem = pxToRem(initialWidthInpx)

      pageLayoutRef.current.classList.add('PageLayout--resizing')

      sidebar.current.style.width = initialWidthInRem + "rem"
      layoutHeaderRef.current.style.width = `calc(100% - ${initialWidthInRem + 3.45}rem)`
      contentRef.current.style.marginLeft = initialWidthInRem + 3.468 + "rem"
      contentRef.current.style.width = `calc(100% - ${initialWidthInRem + 3.62}rem)`

      const setInitialStyles = () => {
        pageLayoutRef?.current?.classList?.remove('PageLayout--resizing')
      }

      requestAnimationFrame(setInitialStyles)
    }
  }, [])

  const handleToggle = () => {
    setLeftNav(!toggleLeftNav)
    let leftSidebarElem: any = sidebar.current
    if (sidebar.current.classList.contains('PageLayout__leftSidebar--show')) {
      setTimeout(function () {
        leftSidebarElem.style.zIndex = '8'
        leftSidebarElem.style.zIndex = props.version === 'v2' ? 'auto' : '8';
      }, 300)
    } else {
      leftSidebarElem.style.zIndex = '2'
    }
    setToggleLayout(!toggleLayout)
  }
  let contentCardClassname = ''
  if (props.type === 'card') {
    contentCardClassname =
      props.headerType === 'custom' ? 'PageLayout__content--card--custom-header' : 'PageLayout__content--card'
  }
  const noSidenavClassName = props.noSideNav ? "PageLayout--primary--no__sidenav" : ""
  const leftSidebarClassName = !!toggleLeftNav ? 'PageLayout__leftSidebar--show' : 'PageLayout__leftSidebar--hide'
  const leftSidebarBackground = props.hasBackground ? 'PageLayout__leftSidebar--pure__white' : ''
  const noLeftnavClassName = props.noLeftNav ? "PageLayout--primary--no__leftnav" : ""
  const breadcrumbMarginClassName = props.breadcrumbMargin ? "PageLayout--primary--breadcrumb__margin" : ''
  const primaryLayoutClassnames = cn("PageLayout PageLayout--primary", noSidenavClassName, noLeftnavClassName, breadcrumbMarginClassName, props.className, {
    "PageLayout--primary--v2": props.version === "v2"
  })
  const resizeableClassName = (props.version === 'v2' && props.resizeable && props?.type === 'list' && !props.noLeftNav) ? 'PageLayout--resize' : ''

  return (
    <div
      ref={pageLayoutRef}
      data-test-id={testId}
      className={`${primaryLayoutClassnames} ${resizeableClassName}`}>
      {props.leftSidebar !== undefined ? (
        !props.noLeftNav && <div
          ref={sidebar}
          className={`PageLayout__leftSidebar ${breadcrumbMarginClassName} ${leftSidebarBackground} ${leftSidebarClassName}`}
          data-test-id={`${testId}-leftSidebar`}>
          <LeftSidebar leftSidebar={props.leftSidebar} />
        </div>
      ) : null}
      <div
        className={`PageLayout__content ${props.leftSidebar === undefined ? 'PageLayout__content--full' : ''
          } ${contentCardClassname} ${toggleLayout ? 'PageLayout__content--full' : ''}`}>
        {props.leftSidebar !== undefined ? (
          <LayoutHeader
            header={props.header}
            type={props.type}
            headerType={props.headerType}
            toggleStat={toggleLeftNav}
            toggle={handleToggle}
            testId={testId}
            version={props.version}
            ref={layoutHeaderRef}
            noLeftNav={props.noLeftNav}
          />
        ) : (
          <LayoutHeader
            header={props.header}
            headerType={props.headerType}
            toggle={handleToggle}
            type={props.type}
            noLeftNav={props.noLeftNav}
            testId={testId}
          />
        )}
        <Content
          content={props.content}
          type={props.type}
          headerType={props.headerType}
          toggle={handleToggle}
          toggleStat={toggleLeftNav}
          version={props.version}
          resizeable={props.resizeable}
          resizableLeftMaxWidth={props?.resizableLeftMaxWidth}
          resizableLeftMinWidth={props?.resizableLeftMinWidth}
          ref={contentRef}
          layoutHeaderRef={layoutHeaderRef}
          pageLayoutRef={pageLayoutRef}
          leftSidebarRef={sidebar}
          setCurrentWidth={props.setCurrentWidth}
          noLeftNav={props.noLeftNav}
          noSideNav={props.noSideNav}
        />
      </div>
    </div >
  )
}

