export const setCaretPos = (input_node, pos) => {
  if (input_node.setSelectionRange) {
    input_node.setSelectionRange(pos, pos)
  } else if (input_node.createTextRange) {
    input_node.createTextRange().move('character', pos)
  }
  input_node.focus()
}

export const setAttributeCollectionOfElement = (eleNodes, key, value) => {
  if (eleNodes.length) {
    let i = 0
    while (i < eleNodes.length) {
      eleNodes[i].setAttribute(key, value)
      i++
    }
  }
}

export const elementMatchesSelector = (eleNode, key) => {
  if (!eleNode || !key) return false
  return eleNode.matches(key)
}


const reorder = <T>(list: T[], startIndex: number, endIndex: number) => {
  const result = Array.from(list)
  const [removed] = result.splice(startIndex, 1)
  result.splice(endIndex, 0, removed)
  return result
}

function encode(val: string): string {
  return val
    .replace(/%3A/gi, ':')
    .replace(/%24/g, '$')
    .replace(/%2C/gi, ',')
    .replace(/%20/g, '+')
    .replace(/%5B/gi, '[')
    .replace(/%5D/gi, ']')
}

function encodeAxiosParam(value: any): string {
  let v = value
  if (value === null) {
    v = ''
    return encodeURIComponent(v)
  }
  if (toString.call(value) === '[object Date]') {
    v = value.toISOString()
  } else if (typeof value === 'object') {
    v = JSON.stringify(value)
  }
  return encodeURIComponent(v)
}

function paramsSerializer(params: any): string {
  const queryString = Object.entries(params)
    .filter(([, value]) => value !== undefined && value !== null && (Array.isArray(value) ? value.length > 0 : true))
    .map(([key, value]) => {
      if (Array.isArray(value)) {
        return value.map((v) => `${key}[]=${encodeAxiosParam(v)}`).join('&')
      }
      return `${key}=${encodeAxiosParam(value)}`
    })
    .join('&')
  return encode(queryString)
}
export class Heap<T> {
  private heap: T[];
  private comparator: (a: T, b: T) => number;

  constructor(comparator: (a: T, b: T) => number) {
    this.heap = [];
    this.comparator = comparator;
  }

  // Insert an element into the heap
  push(value: T): void {
    this.heap.push(value);
    this.heapifyUp(this.heap.length - 1);
  }

  // Extract the maximum element from the heap
  pop(): T | undefined {
    if (this.heap.length === 0) return undefined;

    const max = this.heap[0];
    const end = this.heap.pop();

    if (this.heap.length > 0 && end !== undefined) {
      this.heap[0] = end;
      this.heapifyDown(0);
    }

    return max;
  }

  // Get the current heap as an array
  getHeap(): T[] {
    return [...this.heap];
  }


  // check if the heap is empty
  isEmpty(): boolean {
    return this.heap.length === 0;
  }

  // Helper to maintain heap property after insertion
  private heapifyUp(index: number): void {
    const parentIndex = Math.floor((index - 1) / 2);
    if (index > 0 && this.comparator(this.heap[index], this.heap[parentIndex]) > 0) {
      [this.heap[index], this.heap[parentIndex]] = [this.heap[parentIndex], this.heap[index]];
      this.heapifyUp(parentIndex);
    }
  }

  // Helper to maintain heap property after extraction
  private heapifyDown(index: number): void {
    const length = this.heap.length;
    const leftChild = 2 * index + 1;
    const rightChild = 2 * index + 2;
    let largest = index;

    if (leftChild < length && this.comparator(this.heap[leftChild], this.heap[largest]) > 0) {
      largest = leftChild;
    }

    if (rightChild < length && this.comparator(this.heap[rightChild], this.heap[largest]) > 0) {
      largest = rightChild;
    }

    if (largest !== index) {
      [this.heap[index], this.heap[largest]] = [this.heap[largest], this.heap[index]];
      this.heapifyDown(largest);
    }
  }
}

