export const BulkActionPanelItem = ({ bulkActionList, hanldeClick, showDropdown, sliceCount, activeValue, onActiveValueChange, onClose, arrangeFromStart, originalSliceCount, trimActionsFromLeft=false }) => {
  const [selectedActions, setSelectedActions] = useState(new Set())

  let bulkActionListItems = []
  let trimmedBulkActions = []

  if(trimActionsFromLeft) {
    bulkActionListItems = originalSliceCount > 0 && showDropdown ? [bulkActionList[0], ...bulkActionList.slice(1 + originalSliceCount)] : bulkActionList
    // Everything trimmed off goes here
    trimmedBulkActions = bulkActionList.slice(1, originalSliceCount + 1)
  } else {
    bulkActionListItems = showDropdown ? bulkActionList.slice(0, sliceCount) : bulkActionList
    trimmedBulkActions = bulkActionList.slice(sliceCount, bulkActionList.length)
  }

  // Initialize with activeValue if provided
  useEffect(() => {
    if (activeValue !== undefined && activeValue !== null) {
      setSelectedActions(new Set([activeValue]))
    }
  }, [activeValue])

  const handleActionClick = (action) => {
    if (activeValue !== undefined && activeValue !== null) {
      // Single selection - always set new selection, never deselect
      const actionValue = action.value || action.label
      setSelectedActions(new Set([actionValue]))

      // Update parent state if callback provided
      if (onActiveValueChange) {
        onActiveValueChange(actionValue)
      }
    }
    hanldeClick(action)
  }

  // let bulkActionListItems = showDropdown ? bulkActionList.slice(0, sliceCount) : bulkActionList
  return (
    <div
      className={classnames(
        'TableActionPanel',
        'flex-v-center',
        'Table-bulk-action',
        { 'flex-justify': !arrangeFromStart }
      )}
      tabIndex={0}
    >
      <div className="selected-items" >
        <div className="drag-icon">
          <Tooltip variantType="basic" content="Drag" position="top" showArrow={true}>
            <Icon icon="ActionBar" version='v2' size='small' />
          </Tooltip>
        </div>
      </div>
      <div
        className={classnames(!arrangeFromStart ? 'bulk-action-items' : 'bulk-action-items-arrange-from-start')}
      >
        {bulkActionListItems.map((action: any, i: number) => {
          return (
            <Button
              version="v2"
              id={`bulk-panel-action-item-${i}`}
              testId={action.testId}
              aria-label={action.ariaLabel}
              key={i}
              size="large"
              buttonType={action.type != 'primary' ? action.type : 'light'}
              icon={action.icon ? action.icon : undefined}
              onClick={() => handleActionClick(action)}
              className={classnames(
                action.showSelected && 'show-select-btn',
                activeValue !== undefined && activeValue !== null && selectedActions.has(action.value || action.label) && 'selected-action-btn'
              )}
            // onKeyDown={(e) => {
            //   //reiterating focus through list
            //   if (i === bulkActionListItems.length - 1 && e.key === 'Tab' && !showDropdown) {
            //     setTimeout(() => {
            //       document.getElementById('bulk-panel-action-item-0')?.focus()
            //     })
            //   }
            // }}
            >
              {action.label}
            </Button>
          )
        })}
        {showDropdown > 0 && bulkActionList?.length > bulkActionListItems?.length && (
          <Dropdown
            version="v1"
            list={trimmedBulkActions.map((list, dropdownIndex) => {
              const iconVersion = list?.icon?.includes('v2-') ? 'v2' : 'v1'
              const iconName = iconVersion === 'v2' ? list?.icon?.split('v2-')[1] : list.icon
              const iconClassName = list?.icon === 'Unpublish' ? 'Icon--unpublish' : ''
              return {
                label: (
                  <>
                    <Icon icon={iconName} version={iconVersion} className={iconClassName} />
                    <div data-test-id={list.testId}>{list.label}</div>
                  </>
                ),
                action: () => handleActionClick(list),
                default: true,
              }
            })}
            type="click">
            <div className="see-more-icon" data-test-id={'table-see-more-icon'}>
              <Icon icon="SeeMore" fill="white" size="small" height={24} width={24} />
            </div>
          </Dropdown>
        )}
      </div>
      {
        onClose && (
          <div className="close-button">
            <Button
              buttonType="light"
              onClick={() => onClose()}
              icon={'v2-CloseNoborder'}
              onlyIcon={true}
              size={'medium'}
              version={'v2'}
              iconProps={{ fill: '#F9F8FF' }}
            />
          </div>
        )
      }
    </div >
  )
}
